void m_spel_EventReceived(object sender, SpelEventArgs e)
{ string[] tokens = new string[3]; switch(e.Event) {
    case 2000:
      tokens = e.Message.Split(' ');
      lblCycCount.Text = tokens(0);
      lblLotNumber.Text = tokens(1);
      lblCycTime.Text = tokens(2);
      break;
    default:
      break; }
